+/**
+ * User notification preferences model.
+ *
+ * Controls how and when notifications are delivered to a user.
+ * Currently supports email channel settings. Designed to be extended
+ * with additional channels (webhook, in_app) in the future.
+ */
+
+import type { NotificationType } from './notification.js';
+
+/**
+ * Email-specific notification settings.
+ */
+export interface EmailNotificationPreferences {
+  /** Whether email notifications are enabled globally for this user. */
+  enabled: boolean;
+  /** Per-category opt-in/out. If a category is true, that notification type will be sent. */
+  categories: Record<NotificationType, boolean>;
+}
+
+/**
+ * Full user notification preferences document.
+ */
+export interface UserNotificationPreferences {
+  id: string;
+  userId: string;
+  email: EmailNotificationPreferences;
+  createdAt: Date;
+  updatedAt: Date;
+}
+
+/**
+ * Input for updating notification preferences.
+ * All fields are optional — only provided fields are changed.
+ */
+export interface UpdateNotificationPreferencesInput {
+  email?: {
+    enabled?: boolean;
+    categories?: Partial<Record<NotificationType, boolean>>;
+  };
+}
+
+/**
+ * Returns the default email notification preferences (everything enabled).
+ */
+export function getDefaultEmailPreferences(): EmailNotificationPreferences {
+  return {
+    enabled: true,
+    categories: {
+      order_confirmation: true,
+      order_status_update: true,
+      welcome: true,
+      account_updated: true,
+    },
+  };
+}

