@@ -0,0 +1,118 @@
+/**
+ * Preferences service — business logic for user notification preferences.
+ *
+ * Manages CRUD operations for notification preferences and provides
+ * a query interface for the NotificationService to check whether a
+ * notification should be delivered to a given user.
+ *
+ * Depends on:
+ * - PreferencesRepository (data layer) for persistence
+ */
+
+import type { NotificationType } from '../models/notification.js';
+import type {
+  UserNotificationPreferences,
+  UpdateNotificationPreferencesInput,
+} from '../models/user-preferences.js';
+import { getDefaultEmailPreferences } from '../models/user-preferences.js';
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter (for testing). */
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private preferencesRepository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserNotificationPreferences | undefined {
+    return this.preferencesRepository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating default preferences if none exist.
+   */
+  getOrCreatePreferences(userId: string): UserNotificationPreferences {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+
+    this.logger.info(`Creating default preferences for user ${userId}`);
+    const now = new Date();
+    const preferences: UserNotificationPreferences = {
+      id: generateId(),
+      userId,
+      email: getDefaultEmailPreferences(),
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.preferencesRepository.save(preferences);
+    return preferences;
+  }
+
+  /**
+   * Update notification preferences for a user.
+   * Creates default preferences first if they don't exist, then applies the update.
+   */
+  updatePreferences(
+    userId: string,
+    input: UpdateNotificationPreferencesInput,
+  ): UserNotificationPreferences {
+    const current = this.getOrCreatePreferences(userId);
+    this.logger.info(`Updating preferences for user ${userId}`);
+
+    const updatedEmail = { ...current.email };
+
+    if (input.email) {
+      if (input.email.enabled !== undefined) {
+        updatedEmail.enabled = input.email.enabled;
+      }
+      if (input.email.categories) {
+        updatedEmail.categories = {
+          ...updatedEmail.categories,
+          ...input.email.categories,
+        };
+      }
+    }
+
+    return this.preferencesRepository.update(current.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    });
+  }
+
+  /**
+   * Check whether a notification should be sent to a user via email.
+   *
+   * Returns true if:
+   * - No preferences exist (default: all enabled)
+   * - Email is globally enabled AND the specific category is enabled
+   */
+  isEmailEnabled(userId: string, type: NotificationType): boolean {
+    const preferences = this.preferencesRepository.findByUserId(userId);
+    if (!preferences) {
+      // No preferences stored → default is all enabled
+      return true;
+    }
+
+    if (!preferences.email.enabled) {
+      return false;
+    }
+
+    return preferences.email.categories[type] !== false;
+  }
+}

