+    });
+
+    it('should return false when email is disabled even if category is enabled', () => {
+      service.getOrCreatePreferences('user-0001');
+      service.updatePreferences('user-0001', { email: { enabled: false } });
+      // Categories are still all true, but email is globally off
+      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(false);
+    });
+  });
+});
+
+describe('NotificationService with preferences', () => {
+  let db: Database;
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+  let preferencesRepo: PreferencesRepository;
