/**
 * Dispatch a notification payload through all registered adapters.
 * Checks user preferences before sending (if PreferencesService is set).
 * If no adapters are registered, stores the notification with channel 'email' as a fallback record.
 */
private async dispatch(payload: NotificationPayload): Promise<void> {
  const userId = payload.metadata?.['userId'] as string | undefined;

  if (this.adapters.length === 0) {
    // Check preferences before storing the fallback record
    if (userId && this.preferencesService && !this.preferencesService.isEmailEnabled(userId, payload.type)) {
      this.logger.info(`Notification suppressed for user ${userId}: ${payload.type} (email disabled)`);
      return;
    }
    // No adapters registered — store as in-memory record for backward compatibility
    this.storeNotification(payload, 'email', true);
    return;
  }

  for (const adapter of this.adapters) {
    // Check preferences per channel
    if (userId && this.preferencesService && adapter.channel === 'email') {
      if (!this.preferencesService.isEmailEnabled(userId, payload.type)) {
        this.logger.info(`Notification suppressed for user ${userId}: ${payload.type} (email disabled)`);
        continue;
      }
    }

    const result = await adapter.send(payload);
    this.storeNotification(payload, adapter.channel, result.success, result.error);
  }
}

